import { jsx, jsxs } from 'react/jsx-runtime';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import { useState, useCallback, useMemo, useEffect } from 'react';
import { classNames } from '../../../helpers/classnames.js';
import { Icon } from '../../Icon/Icon.js';
import { PaginationCell } from '../PaginationCell/PaginationCell.js';
import { getPage } from '../utils.js';
import { getStart, getFinish } from './utils.js';

const PaginationCollapsible = ({ count, siblingCount = 3, page = 1, onChange, className, ...props }) => {
    const [_page, _setPage] = useState(getPage(page, count));
    // Кэшируем функцию установки индекса
    const setNewIndex = useCallback((newIndex) => {
        if (newIndex === _page) {
            return;
        }
        _setPage(newIndex);
        onChange?.(newIndex);
    }, [_page, onChange]);
    // Кэшируем обработчик клика
    const handleCellClick = useCallback((newIndex) => {
        setNewIndex(newIndex);
    }, [setNewIndex]);
    // Кэшируем вычисление ячеек страниц
    const siblingCell = useMemo(() => {
        const cells = [];
        const start = getStart(_page, count, siblingCount);
        const finish = getFinish(start, _page, count, siblingCount);
        if (!start || !finish) {
            return cells;
        }
        for (let i = start; i <= finish; i++) {
            const cellIndex = i;
            cells.push(jsx("li", { children: jsx(PaginationCell, { variant: "text", active: _page === cellIndex, onClick: () => handleCellClick(cellIndex), children: cellIndex }) }, cellIndex));
        }
        return cells;
    }, [_page, count, siblingCount, handleCellClick]);
    // Обновление при изменении внешней страницы
    useEffect(() => {
        _setPage(getPage(page, count));
    }, [page, count]);
    const handleDecreaseClick = useCallback(() => {
        const newIndex = _page - 1;
        if (newIndex >= 1) {
            setNewIndex(newIndex);
        }
    }, [_page, setNewIndex]);
    const handleIncreaseClick = useCallback(() => {
        const newIndex = _page + 1;
        if (newIndex <= count) {
            setNewIndex(newIndex);
        }
    }, [_page, count, setNewIndex]);
    const handleFirstCellClick = useCallback(() => {
        handleCellClick(1);
    }, [handleCellClick]);
    const handleLastCellClick = useCallback(() => {
        handleCellClick(count);
    }, [count, handleCellClick]);
    // Кэшируем компоненты
    const navArrowLeft = useMemo(() => (jsx("li", { children: jsx(PaginationCell, { variant: "icon", disabled: _page === 1, startIcon: jsx(Icon, { iconName: Icons.NavArrowLeft, size: "large" }), onClick: handleDecreaseClick, className: "dsb_pagination-cell__first" }) }, 0)), [_page, handleDecreaseClick]);
    const navArrowRight = useMemo(() => (jsx("li", { children: jsx(PaginationCell, { variant: "icon", disabled: _page === count, startIcon: jsx(Icon, { iconName: Icons.NavArrowRight, size: "large" }), onClick: handleIncreaseClick }) }, count ? count + 1 : 2)), [_page, count, handleIncreaseClick]);
    const increaseDots = useMemo(() => (jsx("li", { children: jsx(PaginationCell, { variant: "icon", startIcon: jsx(Icon, { iconName: Icons.MoreHoriz, size: "large" }), className: "dsb_pagination-cell__increase-dots" }) }, 'increase-dots')), []);
    const decreaseDots = useMemo(() => (jsx("li", { children: jsx(PaginationCell, { variant: "icon", startIcon: jsx(Icon, { iconName: Icons.MoreHoriz, size: "large" }), className: "dsb_pagination-cell__decrease-dots" }) }, 'decrease-dots')), []);
    const firstCell = useMemo(() => (jsx("li", { children: jsx(PaginationCell, { variant: "text", active: _page === 1, onClick: handleFirstCellClick, className: "dsb_pagination-cell__first-cell", children: 1 }) }, 1)), [_page, handleFirstCellClick]);
    const lastCell = useMemo(() => (jsx("li", { children: jsx(PaginationCell, { variant: "text", active: _page === count, onClick: handleLastCellClick, className: "dsb_pagination-cell__last-cell", children: count }) }, count)), [_page, count, handleLastCellClick]);
    const showDecreaseDots = useMemo(() => _page > siblingCount + 1 && siblingCount + 3 < count, [_page, siblingCount, count]);
    const showIncreaseDots = useMemo(() => count - _page - 1 >= siblingCount && siblingCount + 3 < count, [_page, siblingCount, count]);
    return (jsxs("ul", { "data-testid": "PaginationCollapsible", className: classNames('dsb_pagination dsb_pagination__collapsed', className), ...props, children: [navArrowLeft, firstCell, showDecreaseDots && decreaseDots, siblingCell, showIncreaseDots && increaseDots, count > 1 && lastCell, navArrowRight] }));
};

export { PaginationCollapsible };
